// ════════════════════════════════════════════════════════════════
// CONFIGURACIÓN — único lugar que tocas para otra temporada
// ════════════════════════════════════════════════════════════════
const config = {
  // Formato con barra — igual que en tu DB
  season_label: '2019/20',

  // Slug de la competition en tu DB
  competition_slug: 'laliga-ea-sports',

  // Wikipedia: título de la temporada (sin https://en.wikipedia.org/wiki/)
  // Patrón: YYYY–YY_La_Liga  (guión largo Unicode en el año)
  wiki_season_title: '2019%E2%80%9320_La_Liga',

  // Transfermarkt
  transfermarkt_competition_code: 'ES1', // LaLiga
  total_matchdays: 38,
};

// ════════════════════════════════════════════════════════════════
// DERIVADOS AUTOMÁTICOS — no tocar
// ════════════════════════════════════════════════════════════════
const seasonCompact = config.season_label.replace('/', ''); // '202021'
const seasonSlug = `laliga-${config.season_label.replace('/', '-')}`; // 'laliga-2020-21'
const wikiUrl = `https://en.wikipedia.org/wiki/${config.wiki_season_title}`;

// Para Transfermarkt, 2020/21 => saison_id=2020
const seasonStartYear = parseInt(config.season_label.split('/')[0], 10);

const transfermarkt_base_url =
  `https://www.transfermarkt.es/laliga/spieltag/wettbewerb/${config.transfermarkt_competition_code}`;

return [{
  json: {
    ...config,

    // Wikipedia
    season_compact: seasonCompact,
    season_slug: seasonSlug,
    wiki_url: wikiUrl,

    // Transfermarkt
    transfermarkt_saison_id: seasonStartYear,
    transfermarkt_base_url,
  }
}];

// Lee todas las competitions y filtra en JS
// Así evitamos el problema de referencias cross-branch en Supabase nodes
const ctx = $('Set Contexto').first().json;

// El nodo Supabase 'Load Competition DB' cargará todas las competitions
// Este nodo solo prepara y pasa el contexto
return [{ json: { ...ctx } }];

// Leer del input directo en lugar de referenciar Set Contexto por nombre
const ctx = $('Set Contexto').first().json;
const allComps = $('Load Competition DB').all().map(i => i.json);

const competition = allComps.find(c => c.slug === ctx.competition_slug);

if (!competition) {
  throw new Error(`Competition no encontrada: "${ctx.competition_slug}"`);
}

return [{
  json: {
    ...ctx,
    competition_id:   competition.id,
    competition_name: competition.name,
  }
}];

// Ahora tenemos competition_id en $json y todas las seasons en Load CompSeason DB
const ctx         = $('Load Competition Season').first().json;
const allSeasons  = $('Load CompSeason DB').all().map(i => i.json);

// Buscar la season correcta: mismo competition_id y season_label
const existing = allSeasons.find(s =>
  s.competition_id === ctx.competition_id &&
  s.season_label   === ctx.season_label
);

if (existing) {
  // Ya existe
  return [{
    json: {
      ...ctx,
      competition_season_id: existing.id,
      _cs_created: false,
    }
  }];
}

// No existe — señal para crear
return [{
  json: {
    ...ctx,
    competition_season_id: null,
    _cs_created: true,
    _cs_insert: {
      competition_id: ctx.competition_id,
      season_label:   ctx.season_label,
      is_current:     false,
      source:         'wikipedia',
    }
  }
}];

const ctx = $input.first().json;
const total = ctx.total_matchdays || 38;

const items = [];

for (let round = 1; round <= total; round++) {
  items.push({
    json: {
      ...ctx,
      round,
      transfermarkt_url: `${ctx.transfermarkt_base_url}/spieltag/${round}/saison_id/${ctx.transfermarkt_saison_id}`,
    }
  });
}

return items;

const inputItems = $input.all();
const output = [];

function stripHtml(s) {
  return (s || '')
    .replace(/<br\s*\/?>/gi, ' ')
    .replace(/<[^>]+>/g, ' ')
    .replace(/&nbsp;/g, ' ')
    .replace(/&amp;/g, '&')
    .replace(/&#160;/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function parseDate(raw) {
  if (!raw) return null;
  const m = raw.match(/(\d{1,2})\/(\d{1,2})\/(\d{4})/);
  if (!m) return null;
  const dd = m[1].padStart(2, '0');
  const mm = m[2].padStart(2, '0');
  const yyyy = m[3];
  return `${yyyy}-${mm}-${dd}`;
}

function parseTime(raw) {
  if (!raw) return null;
  const m = raw.match(/\b(\d{1,2}):(\d{2})H?\b/);
  if (!m) return null;
  return `${m[1].padStart(2, '0')}:${m[2]}`;
}

function compactSlug(s) {
  return (s || '')
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/[^a-z0-9]/g, '');
}

function cleanTeamTitles(titles) {
  const bad = new Set([
    'informe',
    'al hilo de la jornada',
    'al predictor de resultados',
    'transfermarkt',
  ]);

  return titles.filter(t => {
    const v = (t || '').toLowerCase().trim();
    return v && !bad.has(v);
  });
}

for (const wrapped of inputItems) {
  const item = wrapped.json;
  const html = item.data || '';

  const title = html.match(/<title>(.*?)<\/title>/i)?.[1] || '';
  const round =
    parseInt(title.match(/Jornada\s*-\s*(\d+)\./i)?.[1], 10) ||
    parseInt(title.match(/(\d+)\.\s*Jornada/i)?.[1], 10) ||
    item.round ||
    null;

  const season_label = item.season_label || null;
  const season_slug = item.season_slug || null;
  const competition_id = item.competition_id || null;
  const competition_season_id = item.competition_season_id || null;
  const transfermarkt_url = item.transfermarkt_url || null;

  const trs = html.match(/<tr[\s\S]*?<\/tr>/gi) || [];
  const seen = new Set();
  let foundForThisPage = 0;

  for (let i = 0; i < trs.length - 1; i++) {
    const tr1 = trs[i];
    const tr2 = trs[i + 1];

    const text1 = stripHtml(tr1);
    const text2 = stripHtml(tr2);

    const scoreMatch = text1.match(/(\d+):(\d+)/);
    if (!scoreMatch) continue;

    const dateMatch = text2.match(/\b\d{1,2}\/\d{1,2}\/\d{4}\b/);
    const timeMatch = text2.match(/\b\d{1,2}:\d{2}H?\b/);
    if (!dateMatch || !timeMatch) continue;

    const titlesRaw = [...tr1.matchAll(/title="([^"]+)"/gi)]
      .map(m => stripHtml(m[1]))
      .filter(Boolean);

    const titles = cleanTeamTitles(titlesRaw);
    if (titles.length < 2) continue;

    const home_team_raw = titles[0];
    const away_team_raw = titles[titles.length - 1];

    if (!home_team_raw || !away_team_raw) continue;
    if (home_team_raw === away_team_raw) continue;

    const match_date = parseDate(dateMatch[0]);
    const kickoff_time = parseTime(timeMatch[0]);
    if (!match_date || !kickoff_time) continue;

    const home_score = parseInt(scoreMatch[1], 10);
    const away_score = parseInt(scoreMatch[2], 10);

    const key = `${round}_${match_date}_${compactSlug(home_team_raw)}_${compactSlug(away_team_raw)}`;
    if (seen.has(key)) continue;
    seen.add(key);

    foundForThisPage++;

    output.push({
      json: {
        competition_id,
        competition_season_id,
        season: season_label,
        season_slug,
        round,
        match_date,
        kickoff_time,
        home_team_raw,
        away_team_raw,
        home_score,
        away_score,
        transfermarkt_url,
        source: 'transfermarkt',
        _match_key: `${match_date}_${compactSlug(home_team_raw)}_${compactSlug(away_team_raw)}`
      }
    });
  }

  if (!foundForThisPage) {
    output.push({
      json: {
        error: 'no_transfermarkt_matches_found',
        round,
        title,
        transfermarkt_url
      }
    });
  }
}

return output;

function normalizeTeamName(s = '') {
  return String(s || '')
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .toLowerCase()
    .replace(/\b(sd|rc|cf|fc|club|de|del|la|real)\b/g, ' ')
    .replace(/[^a-z0-9]+/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function slugify(s = '') {
  return normalizeTeamName(s).replace(/\s+/g, '-');
}

// Estos nombres tienen que coincidir EXACTAMENTE con tus nodos
const matches = $items("Parse Transfermarkt Matchday").map(i => i.json);
const ctx = $items("Check Competition Season")[0]?.json;
const teams = $items("Load Teams").map(i => i.json);
const aliases = $items("Load Aliases").map(i => i.json);

if (!ctx) {
  return [{
    json: {
      error: 'missing_competition_context'
    }
  }];
}

// Mapa slug -> team_id
const slugToTeamId = {};

// Teams directos
for (const t of teams) {
  if (t.slug) {
    slugToTeamId[String(t.slug).toLowerCase()] = t.id;
  }
}

// Aliases
for (const a of aliases) {
  if (a.alias_slug) {
    slugToTeamId[String(a.alias_slug).toLowerCase()] = a.team_id;
  }
}

const result = matches.map(m => {
  const homeSlug = slugify(m.home_team_raw || '');
  const awaySlug = slugify(m.away_team_raw || '');

  const homeTeamId = slugToTeamId[homeSlug] || null;
  const awayTeamId = slugToTeamId[awaySlug] || null;

  const validationErrors = [];
  if (!homeTeamId) validationErrors.push('missing_home_team_id');
  if (!awayTeamId) validationErrors.push('missing_away_team_id');

  return {
    json: {
      // contexto competición
      competition_id: ctx.competition_id,
      competition_name: ctx.competition_name || null,
      competition_season_id: ctx.competition_season_id,
      season: ctx.season_label || null,
      season_label: ctx.season_label || null,
      season_slug: ctx.season_slug || null,

      // partido
      round: m.round ?? null,
      match_date: m.match_date || null,
      kickoff_time: m.kickoff_time || null,
      home_team_raw: m.home_team_raw || null,
      away_team_raw: m.away_team_raw || null,
      home_score: m.home_score ?? null,
      away_score: m.away_score ?? null,
      transfermarkt_url: m.transfermarkt_url || null,
      source: m.source || 'transfermarkt',
      _match_key: m._match_key || null,
      join_key: m.join_key || null,

      // ids de equipos
      home_team_id: homeTeamId,
      away_team_id: awayTeamId,
      home_team_slug: homeSlug,
      away_team_slug: awaySlug,

      // validación
      validation_errors: validationErrors,
      is_valid: validationErrors.length === 0,
    }
  };
});

return result;

function buildKickoffAt(matchDate, kickoffTime) {
  if (!matchDate || !kickoffTime) return null;
  return `${matchDate}T${kickoffTime}:00`;
}

const items = $input.all().map(i => i.json);

return items.map(j => {
  const validationErrors = Array.isArray(j.validation_errors)
    ? [...j.validation_errors]
    : [];

  if (!j.competition_id) validationErrors.push('missing_competition_id');
  if (!j.competition_season_id) validationErrors.push('missing_competition_season_id');
  if (!j.home_team_id) validationErrors.push('missing_home_team_id');
  if (!j.away_team_id) validationErrors.push('missing_away_team_id');
  if (!j.match_date) validationErrors.push('missing_match_date');

  const kickoffAt = buildKickoffAt(j.match_date, j.kickoff_time);

  return {
    json: {
      competition_id: j.competition_id ?? null,
      competition_season_id: j.competition_season_id ?? null,
      season: j.season || j.season_label || null,
      home_team_id: j.home_team_id ?? null,
      away_team_id: j.away_team_id ?? null,

      stadium_id: null,
      kickoff_at: kickoffAt,
      home_score: j.home_score ?? null,
      away_score: j.away_score ?? null,
      status: 'finished',
      source: j.source || 'transfermarkt',
      source_id: j._match_key || j.join_key || null,

      stage: 'league',
      leg: null,
      is_neutral: false,
      attendance: null,

      kickoff_time: j.kickoff_time || null,
      match_date: j.match_date || null,
      round: j.round ?? null,

      stadium_raw: null,
      city_raw: null,
      season_slug: j.season_slug || null,

      went_extra_time: false,
      went_penalties: false,
      home_penalty_score: null,
      away_penalty_score: null,
      win_method: null,

      // útiles para revisión/debug
      competition_name: j.competition_name || null,
      home_team_raw: j.home_team_raw || null,
      away_team_raw: j.away_team_raw || null,
      home_team_slug: j.home_team_slug || null,
      away_team_slug: j.away_team_slug || null,
      transfermarkt_url: j.transfermarkt_url || null,

      validation_errors: validationErrors,
      is_valid: validationErrors.length === 0,
    }
  };
});

const items = $input.all().map(i => i.json);

const missing = new Map();

for (const j of items) {

  // HOME
  if (!j.home_team_id && j.home_team_raw) {
    const key = j.home_team_raw.toLowerCase();

    if (!missing.has(key)) {
      missing.set(key, {
        team_raw: j.home_team_raw,
        team_slug: j.home_team_slug || null,
        side: 'home'
      });
    }
  }

  // AWAY
  if (!j.away_team_id && j.away_team_raw) {
    const key = j.away_team_raw.toLowerCase();

    if (!missing.has(key)) {
      missing.set(key, {
        team_raw: j.away_team_raw,
        team_slug: j.away_team_slug || null,
        side: 'away'
      });
    }
  }
}

return Array.from(missing.values()).map(x => ({ json: x }));
